import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { Label } from '../components/ui/label';
import { Input } from '../components/ui/input';
import { toast } from 'sonner';
import { Dumbbell, Eye, EyeOff } from 'lucide-react';

export default function LoginPage() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [unverifiedEmail, setUnverifiedEmail] = useState(null); // tracks if last error was unverified
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setUnverifiedEmail(null); // clear any previous unverified message

    try {
      await login(email, password);
      toast.success('Welcome back!');
      navigate('/');
    } catch (error) {
      const detail = error.response?.data?.detail || 'Invalid email or password';
      const isUnverified = error.response?.status === 403 && detail.toLowerCase().includes('verify');

      if (isUnverified) {
        setUnverifiedEmail(email); // show the inline "Verify here" message
      } else {
        toast.error(detail);
      }
    } finally {
      setLoading(false); // ALWAYS reset button, no matter what
    }
  };

  // Reset unverified message when user starts typing again
  const handleEmailChange = (e) => {
    setEmail(e.target.value);
    setUnverifiedEmail(null);
  };

  const handlePasswordChange = (e) => {
    setPassword(e.target.value);
    setUnverifiedEmail(null);
  };

  return (
    <div className="min-h-screen bg-[#0A0A0A] flex items-center justify-center p-4">
      <div className="w-full max-w-md">
        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center w-16 h-16 bg-[#007AFF] rounded-md mb-4">
            <Dumbbell className="w-8 h-8 text-white" />
          </div>
          <h1 className="barlow text-4xl font-black tracking-tighter text-white mb-2">FITTRACK</h1>
          <p className="text-[#A1A1AA] tracking-wide">Track your gains, build your strength</p>
        </div>

        <div className="bg-[#1A1A1A] border border-[#27272A] rounded-md p-8">
          <h2 className="barlow text-2xl font-bold tracking-tight text-white mb-6">Login</h2>

          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="email" className="text-sm font-medium text-white uppercase tracking-widest">
                Email
              </Label>
              <Input
                id="email"
                type="email"
                value={email}
                onChange={handleEmailChange}
                required
                className="bg-[#0A0A0A] border-[#27272A] text-white focus:border-[#007AFF] focus:ring-2 focus:ring-[#007AFF]"
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="password" className="text-sm font-medium text-white uppercase tracking-widest">
                Password
              </Label>
              <div className="relative">
                <Input
                  id="password"
                  type={showPassword ? 'text' : 'password'}
                  value={password}
                  onChange={handlePasswordChange}
                  required
                  className="bg-[#0A0A0A] border-[#27272A] text-white focus:border-[#007AFF] focus:ring-2 focus:ring-[#007AFF] pr-10"
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-[#71717A] hover:text-[#007AFF] transition-colors"
                  tabIndex={-1}
                >
                  {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                </button>
              </div>
            </div>

            {/* Unverified account inline error */}
            {unverifiedEmail && (
              <div className="bg-[#FF9F0A]/10 border border-[#FF9F0A]/40 rounded-md px-4 py-3 flex items-center justify-between gap-3">
                <p className="text-[#FF9F0A] text-sm">Account not verified.</p>
                <button
                  type="button"
                  onClick={() => navigate('/verify-email', { state: { email: unverifiedEmail } })}
                  className="text-[#FF9F0A] hover:text-white text-sm font-bold underline underline-offset-2 whitespace-nowrap transition-colors"
                >
                  Verify here →
                </button>
              </div>
            )}

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-[#007AFF] hover:bg-[#0066DD] disabled:opacity-50 text-white font-bold py-3 rounded-md transition-colors"
            >
              {loading ? 'Logging in...' : 'Login'}
            </button>
          </form>

          <div className="mt-6 text-center">
            <p className="text-[#A1A1AA] text-sm">
              Don't have an account?{' '}
              <Link to="/register" className="text-[#007AFF] hover:text-[#0066DD] font-medium">
                Sign up
              </Link>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}
